# Test Python imports
from tensorrt_llm.quantization.mode import QuantAlgo, QuantMode

# Test that the enum value exists
try:
    print("✓ QuantAlgo.W4A8_MXFP4_INT8 =", QuantAlgo.W4A8_MXFP4_INT8)
except AttributeError as e:
